#!/usr/bin/env node
// Copyright (c) Rivoli AI 2026. All rights reserved.
//
// set-environment.js — generate src/environments/environment.<mode>.ts files
// from a per-mode .env file at the repo root.
//
// The Angular build is compile-time, so runtime env vars cannot reach the
// browser bundle. This script substitutes values into a template literal and
// writes one TypeScript file per mode. Source of truth: .env.<mode> at the
// repo root, generated by scripts/sync-dep-ports.sh.
//
// Usage:
//   node client/scripts/set-environment.js              # all four modes
//   node client/scripts/set-environment.js --mode=docker  # one mode
//
// Modes -> output:
//   dotnet    -> src/environments/environment.ts        (default Angular dev)
//   docker    -> src/environments/environment.docker.ts
//   embedded  -> src/environments/environment.embedded.ts
//   prod      -> src/environments/environment.prod.ts   (CI: reads process.env, not a file)

'use strict';

const fs = require('fs');
const path = require('path');

const REPO_ROOT = path.resolve(__dirname, '..', '..');
const ENV_DIR = path.join(REPO_ROOT, 'client', 'src', 'environments');

const MODE_TO_OUTPUT = {
  dotnet: 'environment.ts',
  docker: 'environment.docker.ts',
  embedded: 'environment.embedded.ts',
  prod: 'environment.prod.ts',
};

function parseEnvFile(filePath) {
  if (!fs.existsSync(filePath)) return {};
  const out = {};
  for (const line of fs.readFileSync(filePath, 'utf8').split('\n')) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const eq = trimmed.indexOf('=');
    if (eq < 0) continue;
    out[trimmed.slice(0, eq)] = trimmed.slice(eq + 1);
  }
  return out;
}

function loadEnvForMode(mode) {
  // prod: CI populates process.env directly — no .env file expected.
  if (mode === 'prod') return process.env;
  const file = path.join(REPO_ROOT, `.env.${mode}`);
  const fromFile = parseEnvFile(file);
  return { ...fromFile, ...process.env };
}

function require_(env, key) {
  const value = env[key];
  if (value == null || value === '') {
    throw new Error(`missing required env var: ${key}`);
  }
  return value;
}

function render(mode, env) {
  const isProd = mode === 'prod';
  const authAuthority = isProd ? require_(env, 'ANDY_AUTH_AUTHORITY') : (env.ANDY_AUTH_AUTHORITY || '');
  const clientId = require_(env, 'ANDY_FRONTEND_AUTH_CLIENT_ID');
  return [
    '// Generated by client/scripts/set-environment.js — do not edit by hand.',
    `// Mode: ${mode}. Source: ${isProd ? 'process.env (CI)' : `.env.${mode}`}.`,
    'export const environment = {',
    `  production: ${isProd},`,
    `  apiUrl: '/api',`,
    `  authAuthority: '${authAuthority}',`,
    `  authClientId: '${clientId}',`,
    '};',
    '',
  ].join('\n');
}

function writeMode(mode) {
  const env = loadEnvForMode(mode);
  const content = render(mode, env);
  const target = path.join(ENV_DIR, MODE_TO_OUTPUT[mode]);
  fs.mkdirSync(ENV_DIR, { recursive: true });
  fs.writeFileSync(target, content);
  console.log(`wrote ${path.relative(REPO_ROOT, target)}`);
}

function main() {
  const args = process.argv.slice(2);
  const modeArg = args.find((a) => a.startsWith('--mode='));
  const modes = modeArg ? [modeArg.slice('--mode='.length)] : Object.keys(MODE_TO_OUTPUT);
  for (const mode of modes) {
    if (!(mode in MODE_TO_OUTPUT)) {
      console.error(`unknown mode: ${mode}. Valid: ${Object.keys(MODE_TO_OUTPUT).join(', ')}`);
      process.exit(2);
    }
    writeMode(mode);
  }
}

main();
